// @trace-pilot 4e1c1c80e648b5948effb790fb754e946b3446ab
//PPU registers
use crate::cartridge::Mirroring;
use registers::control::ControlRegister;
use registers::mask::MaskRegister;
use registers::status::StatusRegister;
use registers::scroll::ScrollRegister;
use registers::addr::AddrRegister;

pub mod registers;

pub struct NesPPU{
    pub chr_rom: Vec<u8>,
    pub mirroring: Mirroring,
    pub ctrl: ControlRegister,
    pub mask: MaskRegister,
    pub status: StatusRegister,
    pub scroll: ScrollRegister,
    pub addr: AddrRegister,
    pub vram: [u8;2048], // 2KB

    pub oam_addr: u8,
    pub oam_data: [u8;256],
    pub palette_table:[u8;32],

    // ppuデータ保存レジスタ
    internal_data_buf: u8,

    scanline: u16,
    cycles: usize,
    pub nmi_interrupt: Option<u8>,
}

pub trait PPU{
    fn write_to_ctrl(&mut self,value:u8);
    fn write_to_mask(&mut self,value:u8);
    fn read_status(&mut self)->u8;
    fn write_to_oam_addr(&mut self,value:u8);
    fn write_to_oam_data(&mut self,value:u8);
    fn read_oam_data(&self)->u8;
    fn write_to_scroll(&mut self,value:u8);
    fn write_to_ppu_addr(&mut self,value: u8);
    fn write_to_data(&mut self,value:u8);
    fn read_data(&mut self)->u8;
    fn write_oam_dma(&mut self,value: &[u8;256]);
}

impl NesPPU{
    pub fn new_empty_rom() -> Self{
        NesPPU::new(vec![0;2048],Mirroring::Horizontal)
    }
    pub fn new(chr_rom: Vec<u8>,mirroring: Mirroring) -> Self{
        NesPPU{
            chr_rom: chr_rom,
            mirroring: mirroring,
            ctrl: ControlRegister::new(),
            mask: MaskRegister::new(),
            status: StatusRegister::new(),
            oam_addr: 0,
            scroll: ScrollRegister::new(),
            addr: AddrRegister::new(),

            vram: [0;2048],
            oam_data: [0;256],
            palette_table: [0;32],
            internal_data_buf: 0,

            cycles: 0,
            scanline: 0,
            nmi_interrupt: None,
        }
    }
    // Horizontal:
    //   [ A ] [ a ]
    //   [ B ] [ b ]

    // Vertical:
    //   [ A ] [ B ]
    //   [ a ] [ b ]
    // @trace-pilot ad228abc9ce23e09608ac2df31c2b3b819482b33
    //Mirroring
    // @trace-pilot 43568640e8139bf370eb703b9bc9165e6d4325fe
    //PPUアドレス（$2000〜$2FFF）を、実際の2KB VRAMの位置に変換している
    pub fn mirror_vram_addr(&self,addr:u16) ->u16{
        let mirrored_vram=addr &0b1011_1111_1111_1111;
        let vram_index=mirrored_vram - 0x2000;
        let name_table=vram_index /0x400;
        match(&self.mirroring,name_table){
            (Mirroring::Vertical,2) | (Mirroring::Vertical,3) => vram_index - 0x800,
            (Mirroring::Horizontal,2) => vram_index - 0x400,
            (Mirroring::Horizontal,1) => vram_index - 0x400,
            (Mirroring::Horizontal,3) => vram_index - 0x800,
            _ => vram_index,
        }
    }

    fn increment_vram_addr(&mut self){
        self.addr.increment(self.ctrl.vram_addr_increment());
    }

    pub fn tick(&mut self,cycles: u8) -> bool{
        self.cycles += cycles as usize;
        // @trace-pilot df34a82a31f4146f1092f50f9c2e2343a0f2b055
        // Each scanline lasts for 341 PPU clock cycles
        if self.cycles >=341{
            self.cycles=self.cycles-341;
            self.scanline+=1;

            // @trace-pilot 0c847a11069af367946168c8395a2ad8373d4629
            // Start of vertical blanking (scanline 241, dot 1): Set vblank_flag in PPU to true
            if self.scanline==241{
                self.status.set_vblank_status(true);
                self.status.set_sprite_zero_hit(false);
                // 描画しても良い状態か
                if self.ctrl.generate_vblank_nmi(){
                    self.nmi_interrupt=Some(1);
                }
            }
            // @trace-pilot d6c688eaaf4a4f9a02ad64efb3d8af0d09a33ae9
            // The PPU renders 262 scanlines per frame
            if self.scanline >=262{
                self.scanline=0;
                self.nmi_interrupt=None;
                self.status.set_sprite_zero_hit(false);
                self.status.reset_vblank_status();
                return true;
            }
        }
        return false;
    }

    pub fn poll_nmi_interrupt(&mut self) -> Option<u8>{
        self.nmi_interrupt.take()
    }
}

impl PPU for NesPPU{
    fn write_to_ctrl(&mut self,value: u8){
        let before_nmi_status=self.ctrl.generate_vblank_nmi();
        self.ctrl.update(value);
        if !before_nmi_status & self.ctrl.generate_vblank_nmi() && self.status.is_in_vblank(){
            self.nmi_interrupt=Some(1);
        }
    }

    fn write_to_mask(&mut self,value:u8){
        self.mask.update(value);
    }

    fn read_status(&mut self)->u8{
        let data=self.status.snapshot();
        self.status.reset_vblank_status();
        self.addr.reset_latch();
        self.scroll.reset_latch();
        data
    }

    fn write_to_oam_addr(&mut self,value:u8){
        self.oam_addr=value;
    }

    fn write_to_oam_data(&mut self,value:u8){
        self.oam_data[self.oam_addr as usize]=value;
        self.oam_addr=self.oam_addr.wrapping_add(1);
    }

    fn read_oam_data(&self) -> u8 {
        self.oam_data[self.oam_addr as usize]
    }

    fn write_to_scroll(&mut self,value:u8){
        self.scroll.write(value);
    }

    fn write_to_ppu_addr(&mut self,value:u8){
        self.addr.update(value);
    }

    fn write_to_data(&mut self,value:u8){
        let addr=self.addr.get();
        match addr{
            0..=0x1fff => println!("attempt to write to chr rom space {}",addr),
            0x2000..=0x2fff =>{
                self.vram[self.mirror_vram_addr(addr) as usize]=value;
            }
            0x3000..=0x3eff => unimplemented!("addr {} should not be used in reallity",addr),

            0x3f10 | 0x3f14 | 0x3f18 | 0x3f1c =>{
                let add_mirror=addr-0x10;
                self.palette_table[(add_mirror - 0x3f00) as usize]=value;
            }
            0x3f00..=0x3fff=>{
                self.palette_table[(addr-0x3f00) as usize]=value;
            }
            _ => panic!("unexpected access to mirrored space {}",addr),
        }
        // @trace-pilot ce4fccd0b1086b3af0cd2a3b3bf74a0d7b8e0cbc
        // it will cause graphical glitches
        self.increment_vram_addr();
    }

    fn read_data(&mut self)->u8{
        let addr=self.addr.get();
        // @trace-pilot ce4fccd0b1086b3af0cd2a3b3bf74a0d7b8e0cbc
        // it will cause graphical glitches
        self.increment_vram_addr();

        match addr{
            0..=0x1fff =>{
                let result=self.internal_data_buf;
                self.internal_data_buf=self.chr_rom[addr as usize];
                result
            }
            0x2000..=0x2fff=>{
                let result=self.internal_data_buf;
                self.internal_data_buf=self.vram[self.mirror_vram_addr(addr) as usize];
                result
            }
            0x3000..=0x3eff=>{
                unimplemented!("addr {} should not used in reallity",addr);
            }
            0x3f10 | 0x3f14 | 0x3f18 | 0x3f1c =>{
                let add_mirror=addr-0x10;
                self.palette_table[(add_mirror - 0x3f00) as usize]
            }
            0x3f00..0x3fff=>{
                self.palette_table[(addr-0x3f00) as usize]
            }
            _ =>panic!("unexpected access to mirrored space {}",addr),
        }
    }

    fn write_oam_dma(&mut self, data: &[u8; 256]) {
        for x in data.iter() {
            self.oam_data[self.oam_addr as usize] = *x;
            self.oam_addr = self.oam_addr.wrapping_add(1);
        }
    }
}

